t.script:
function shareRegulation() {
    if (navigator.share) {
        navigator.share({
            title: document.title,
            text: 'Lihat peraturan ini',
            url: window.location.href
        });
    } else {
        navigator.clipboard.writeText(window.location.href).then(function() {
            alert('URL berhasil disalin ke clipboard!');
        });
    }
}

// Font size adjustment
let currentFontSize = 16;
function adjustFontSize(delta) {
    currentFontSize = Math.max(12, Math.min(24, currentFontSize + delta));
    document.querySelectorAll('.regulation-content-main').forEach(el => {
        el.style.fontSize = currentFontSize + 'px';
    });
}

// Fullscreen toggle
function toggleFullscreen() {
    const content = document.querySelector('.regulation-content-main');
    if (content.style.maxHeight !== 'none') {
        content.style.maxHeight = 'none';
        content.style.position = 'fixed';
        content.style.top = '0';
        content.style.left = '0';
        content.style.right = '0';
        content.style.bottom = '0';
        content.style.zIndex = '9999';
        content.style.background = 'white';
        content.style.padding = '40px';
    } else {
        content.style.maxHeight = 'calc(100vh - 250px)';
        content.style.position = '';
        content.style.top = '';
        content.style.left = '';
        content.style.right = '';
        content.style.bottom = '';
        content.style.zIndex = '';
        content.style.padding = '';
    }
}

// Store TOC elements globally
window.tocElements = {};

// Toggle collapse for BAB items (only toggle, no scroll)
window.toggleBab = function(babId, evt) {
    if (evt) {
        evt.preventDefault();
        evt.stopPropagation();
    }
    const subItems = document.getElementById('sub-' + babId);
    const icon = document.getElementById('icon-' + babId);
    if (subItems) {
        if (subItems.style.display === 'none') {
            subItems.style.display = 'block';
            if (icon) icon.className = 'fa fa-chevron-down fa-fw';
        } else {
            subItems.style.display = 'none';
            if (icon) icon.className = 'fa fa-chevron-right fa-fw';
        }
    }
    return false;
};

// Scroll to TOC element AND expand if it's a BAB
window.scrollToTocElement = function(key, evt) {
    if (evt) {
        evt.preventDefault();
        evt.stopPropagation();
    }

    // If clicking a BAB, also expand it
    if (key.startsWith('BAB-')) {
        const subItems = document.getElementById('sub-' + key);
        const icon = document.getElementById('icon-' + key);
        if (subItems && subItems.style.display === 'none') {
            subItems.style.display = 'block';
            if (icon) icon.className = 'fa fa-chevron-down fa-fw';
        }
    }

    const element = window.tocElements[key];
    const scrollContainer = document.querySelector('.regulation-content-main');

    if (element && scrollContainer) {
        const containerRect = scrollContainer.getBoundingClientRect();
        const elementRect = element.getBoundingClientRect();
        const scrollTop = scrollContainer.scrollTop + (elementRect.top - containerRect.top) - 30;

        scrollContainer.scrollTo({
            top: scrollTop,
            behavior: 'smooth'
        });

        // Update active state
        document.querySelectorAll('.toc-item, .toc-sub-item').forEach(l => l.classList.remove('active'));
        if (evt && evt.target) {
            const targetEl = evt.target.closest('a, span');
            if (targetEl) targetEl.classList.add('active');
        }
    }
    return false;
};

// Generate dynamic TOC from content
document.addEventListener('DOMContentLoaded', function() {
    const scrollContainer = document.querySelector('.regulation-content-main');
    const tocNav = document.getElementById('toc-nav');
    const tocBabContainer = document.getElementById('toc-bab-container');

    if (!scrollContainer || !tocBabContainer) return;

    // ============================
    // DEEP LINK SYSTEM
    // ============================

    // Create toast element for "Link copied" notification
    const toast = document.createElement('div');
    toast.className = 'deep-link-toast';
    toast.textContent = 'Link berhasil disalin!';
    document.body.appendChild(toast);

    function showToast(msg) {
        toast.textContent = msg || 'Link berhasil disalin!';
        toast.classList.add('show');
        setTimeout(() => toast.classList.remove('show'), 2000);
    }

    // Generate a slug from text
    function slugify(text) {
        return text
            .toLowerCase()
            .replace(/[^\w\s-]/g, '')
            .replace(/\s+/g, '-')
            .replace(/-+/g, '-')
            .trim();
    }

    // Assign IDs and add link buttons to content elements
    const linkableSelectors = 'h3, h4, h5, h6, p, li, .penjelasan';
    const contentElements = scrollContainer.querySelectorAll(linkableSelectors);
    const usedIds = {};
    let sectionCounter = 0;

    contentElements.forEach(el => {
        // For elements inside .penjelasan:
        // - Allow .penjelasan div itself (it has the class)
        // - Allow p elements (content paragraphs)
        // - Skip everything else (title divs, spans, etc.)
        if (el.closest('.penjelasan') && !el.classList.contains('penjelasan')) {
            if (el.tagName !== 'P') return;
        }
        // Skip very short/empty elements
        const text = el.textContent.trim();
        if (!text || text.length < 2) return;
        // Skip elements inside TOC
        if (el.closest('#toc-nav') || el.closest('#toc-container')) return;

        sectionCounter++;

        // Generate ID based on content
        let elementId = '';
        const babMatch = text.match(/^BAB\s+([IVXLCDM]+|\d+)/i);
        const pasalMatch = text.match(/^Pasal\s+(\d+[A-Z]?)/i);
        const ayatMatch = text.match(/^\((\d+)\)/);

        if (babMatch) {
            elementId = 'bab-' + babMatch[1].toLowerCase();
        } else if (pasalMatch) {
            elementId = 'pasal-' + pasalMatch[1].toLowerCase();
        } else if (ayatMatch) {
            elementId = 'ayat-' + ayatMatch[1] + '-s' + sectionCounter;
        } else if (el.classList.contains('penjelasan')) {
            // The penjelasan box itself
            var penjBox = el;
            var penjTitleDiv = penjBox.querySelector('div');
            var penjTitleText = penjTitleDiv ? penjTitleDiv.textContent.trim() : '';
            var penjM = penjTitleText.match(/Penjelasan\s+(.+?)\]/i);
            var penjLbl = penjM ? slugify(penjM[1]).substring(0, 25) : sectionCounter;
            elementId = 'penjelasan-' + penjLbl;
        } else if (el.tagName === 'P' && el.closest('.penjelasan')) {
            // A paragraph inside penjelasan
            var penjParent = el.closest('.penjelasan');
            var pTitleDiv = penjParent.querySelector('div');
            var pTitleTxt = pTitleDiv ? pTitleDiv.textContent.trim() : '';
            var pM = pTitleTxt.match(/Penjelasan\s+(.+?)\]/i);
            var pLbl = pM ? slugify(pM[1]).substring(0, 25) : sectionCounter;
            elementId = 'penjelasan-p-' + pLbl + '-' + sectionCounter;
        } else {
            // For paragraphs, use first few words
            const slug = slugify(text.substring(0, 50));
            elementId = slug ? slug.substring(0, 40) : 's-' + sectionCounter;
        }

        // Ensure unique
        if (usedIds[elementId]) {
            elementId = elementId + '-' + sectionCounter;
        }
        usedIds[elementId] = true;

        // Set ID on element
        el.id = elementId;

        // For .penjelasan div: only set ID for hash nav, skip link button
        // (child p elements will get their own individual link buttons)
        if (el.classList.contains('penjelasan')) return;

        // Wrap in linkable-section container
        el.classList.add('linkable-section');

        // Create link button
        const linkBtn = document.createElement('button');
        linkBtn.className = 'deep-link-btn';
        linkBtn.innerHTML = '<i class="fa fa-link"></i>';
        linkBtn.title = 'Salin link ke bagian ini';
        linkBtn.setAttribute('data-section-id', elementId);

        linkBtn.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            const sectionId = this.getAttribute('data-section-id');
            const url = window.location.origin + window.location.pathname + '#' + sectionId;

            // Update URL without scrolling
            history.replaceState(null, null, '#' + sectionId);

            // Copy to clipboard
            navigator.clipboard.writeText(url).then(function() {
                showToast('Link berhasil disalin!');
            }).catch(function() {
                // Fallback
                const temp = document.createElement('textarea');
                temp.value = url;
                document.body.appendChild(temp);
                temp.select();
                document.execCommand('copy');
                document.body.removeChild(temp);
                showToast('Link berhasil disalin!');
            });

            // Highlight the section briefly
            highlightSection(sectionId);
        });

        el.appendChild(linkBtn);
    });

    // Highlight a section by id
    function highlightSection(sectionId) {
        // Remove previous highlight
        document.querySelectorAll('.linkable-section.highlighted').forEach(el => {
            el.classList.remove('highlighted');
        });
        const target = document.getElementById(sectionId);
        if (target) {
            target.classList.add('highlighted');
            // Remove highlight after 5 seconds
            setTimeout(() => target.classList.remove('highlighted'), 5000);
        }
    }

    // Scroll to hash on page load
    function scrollToHash() {
        const hash = window.location.hash;
        if (hash && hash.length > 1) {
            const targetId = hash.substring(1);
            const target = document.getElementById(targetId);
            if (target) {
                // Wait a moment for layout
                setTimeout(function() {
                    const containerRect = scrollContainer.getBoundingClientRect();
                    const elementRect = target.getBoundingClientRect();
                    const scrollTop = scrollContainer.scrollTop + (elementRect.top - containerRect.top) - 60;

                    scrollContainer.scrollTo({
                        top: scrollTop,
                        behavior: 'smooth'
                    });

                    highlightSection(targetId);
                }, 500);
            }
        }
    }

    // Listen for hash changes
    window.addEventListener('hashchange', scrollToHash);

    // ============================
    // TABLE OF CONTENTS BUILDER
    // ============================

    // Find all BAB and Pasal in content
    const contentText = scrollContainer.innerHTML;
    const allElements = scrollContainer.querySelectorAll('*');

    // Structure to hold BAB -> Pasal mapping
    const structure = {};
    let currentBab = null;

    // Regex patterns
    const babPattern = /^BAB\s+([IVXLCDM]+|[0-9]+)/i;
    const pasalPattern = /^Pasal\s+(\d+[A-Z]?)/i;

    allElements.forEach(el => {
        const text = el.textContent.trim();
        const directText = Array.from(el.childNodes)
            .filter(node => node.nodeType === 3)
            .map(node => node.textContent.trim())
            .join(' ').trim();

        // Check for BAB
        const babMatch = directText.match(babPattern) || text.substring(0, 20).match(babPattern);
        if (babMatch && !el.closest('.toc-item')) {
            const babNum = babMatch[1];
            const babKey = 'BAB-' + babNum;
            if (!structure[babKey]) {
                structure[babKey] = {
                    element: el,
                    title: 'BAB ' + babNum,
                    pasals: []
                };
                currentBab = babKey;
                window.tocElements[babKey] = el;
            }
        }

        // Check for Pasal
        const pasalMatch = directText.match(pasalPattern) || text.substring(0, 15).match(pasalPattern);
        if (pasalMatch && currentBab && !el.closest('.toc-item')) {
            const pasalNum = pasalMatch[1];
            const pasalKey = currentBab + '-Pasal-' + pasalNum;
            // Avoid duplicates
            if (!structure[currentBab].pasals.find(p => p.key === pasalKey)) {
                structure[currentBab].pasals.push({
                    key: pasalKey,
                    element: el,
                    title: 'Pasal ' + pasalNum
                });
                window.tocElements[pasalKey] = el;
            }
        }
    });

    // Generate TOC HTML
    let tocHtml = '';
    Object.keys(structure).forEach(babKey => {
        const bab = structure[babKey];
        const hasPasals = bab.pasals.length > 0;

        tocHtml += '<div class="toc-bab-item">';
        tocHtml += '<a class="nav-link small py-1 px-2 toc-item d-flex align-items-center" href="javascript:void(0)" ';
        tocHtml += "onclick=\"scrollToTocElement('" + babKey + "', event); return false;\">";

        if (hasPasals) {
            tocHtml += "<span class=\"me-1\" style=\"cursor:pointer\" onclick=\"toggleBab('" + babKey + "', event); return false;\">";
            tocHtml += '<i id="icon-' + babKey + '" class="fa fa-chevron-right fa-fw"></i>';
            tocHtml += '</span>';
        } else {
            tocHtml += '<i class="fa fa-bookmark-o fa-fw me-1"></i>';
        }

        tocHtml += bab.title + '</a>';

        // Sub-items (Pasals)
        if (hasPasals) {
            tocHtml += '<div id="sub-' + babKey + '" class="toc-sub-items ps-3" style="display:none;">';
            bab.pasals.forEach(pasal => {
                tocHtml += '<span class="nav-link small py-0 px-2 toc-sub-item" style="cursor:pointer; font-size: 0.75rem;" ';
                tocHtml += "onclick=\"scrollToTocElement('" + pasal.key + "', event); return false;\">";
                tocHtml += '<i class="fa fa-angle-right fa-fw"></i> ' + pasal.title + '</span>';
            });
            tocHtml += '</div>';
        }

        tocHtml += '</div>';
    });

    tocBabContainer.innerHTML = tocHtml;

    // Handle clicks on static TOC items (Pembukaan, Penjelasan)
    tocNav.addEventListener('click', function(e) {
        const link = e.target.closest('a.toc-item[data-search]');
        if (link) {
            e.preventDefault();
            const searchTerms = link.getAttribute('data-search');
            if (searchTerms) {
                const terms = searchTerms.split(',').map(t => t.trim());

                for (let el of allElements) {
                    const text = el.textContent.trim().toUpperCase();
                    for (let term of terms) {
                        if (text.startsWith(term.toUpperCase()) || text.includes(term.toUpperCase())) {
                            const containerRect = scrollContainer.getBoundingClientRect();
                            const elementRect = el.getBoundingClientRect();
                            const scrollTop = scrollContainer.scrollTop + (elementRect.top - containerRect.top) - 30;

                            scrollContainer.scrollTo({
                                top: scrollTop,
                                behavior: 'smooth'
                            });

                            document.querySelectorAll('.toc-item, .toc-sub-item').forEach(l => l.classList.remove('active'));
                            link.classList.add('active');
                            return;
                        }
                    }
                }
            }
        }
    });

    // After TOC is built, scroll to hash if present in URL
    scrollToHash();
});
